package com.example.bankingapp;

import android.os.Bundle;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {

    private AccountManager accountManager;
    private TextView balanceTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        balanceTextView = findViewById(R.id.balanceTextView);
        accountManager = new AccountManager();

        displayBalance();
    }

    private void displayBalance() {
        double balance = accountManager.getAccountBalance();
        balanceTextView.setText("Balance: $" + balance);
    }
}

// AccountManager.java
package com.example.bankingapp;

public class AccountManager {

    private double accountBalance;

    public AccountManager() {
        // Initialize with a default balance
        this.accountBalance = 1000.00;
    }

    public double getAccountBalance() {
        return accountBalance;
    }

    public boolean processTransaction(double amount) {
        if (amount < 0 && Math.abs(amount) > accountBalance) {
            return false; // Insufficient funds
        }
        accountBalance += amount;
        return true;
    }
}

